+  -----------------------------------------------------------------------------
+  -- Function to or together all bits in a vector.
+  -----------------------------------------------------------------------------
+  function or_reduce( V: std_logic_vector )
+    return std_ulogic is
+    variable result: std_ulogic;
+  begin
+    for i in V'range loop
+      if i = V'left then
+        result := V(i);
+      else
+        result := result or V(i);
+      end if;
+      exit when result = '1';
+    end loop;
+    return result;
+  end function;
